import os, zipfile, xml.etree.ElementTree as ET, re
from pathlib import Path

def extract_text_xlsx(path, limit=80):
    out=[]
    try:
        with zipfile.ZipFile(path) as z:
            ns={'a':'http://schemas.openxmlformats.org/spreadsheetml/2006/main','r':'http://schemas.openxmlformats.org/officeDocument/2006/relationships'}
            ss=[]
            if 'xl/sharedStrings.xml' in z.namelist():
                root=ET.fromstring(z.read('xl/sharedStrings.xml'))
                for si in root.findall('a:si',ns):
                    ss.append(''.join(t.text or '' for t in si.iterfind('.//a:t',ns)))
            wb=ET.fromstring(z.read('xl/workbook.xml'))
            rels=ET.fromstring(z.read('xl/_rels/workbook.xml.rels'))
            rmap={rel.attrib['Id']:rel.attrib['Target'] for rel in rels}
            sheets=wb.find('a:sheets',ns)
            if sheets is None:
                return []
            for sheet in sheets[:1]:
                rid=sheet.attrib.get('{http://schemas.openxmlformats.org/officeDocument/2006/relationships}id')
                target='xl/'+rmap[rid]
                root=ET.fromstring(z.read(target))
                for c in root.iter('{http://schemas.openxmlformats.org/spreadsheetml/2006/main}c'):
                    v=c.find('{http://schemas.openxmlformats.org/spreadsheetml/2006/main}v')
                    if v is None: continue
                    val=v.text or ''
                    if c.attrib.get('t')=='s':
                        try: val=ss[int(val)]
                        except: pass
                    out.append(val)
                    if len(out)>=limit: return out
    except Exception:
        return []
    return out

keywords=['task','owner','priority','status','milestone','sprint','due date','assignee','开发','任务','负责人','优先级','状态','里程碑','排期']
for root, dirs, files in os.walk('.', topdown=True):
    dirs[:] = [d for d in dirs if d not in ['model_output','kg']]
    for f in files:
        if f.lower().endswith('.xlsx'):
            path=os.path.join(root,f)
            vals=extract_text_xlsx(path)
            blob=' '.join(vals).lower()
            score=sum(1 for k in keywords if k in blob)
            if score>=2:
                print(score, path)
